+void
+gimp_displays_invalidate (Gimp *gimp)
+{
+  GList       *list;
+  GimpDisplay *gdisp;
+
+  g_return_if_fail (GIMP_IS_GIMP (gimp));
+
+  for (list = GIMP_LIST (gimp->displays)->list;
+       list;
+       list = g_list_next (list))
+    {
